#!/usr/bin/env node

import fs from "node:fs";

function fail(message) {
  console.error(message);
  process.exit(1);
}

function loadReport(path) {
  let content;
  try {
    content = fs.readFileSync(path, "utf8");
  } catch (error) {
    fail(`Failed to read hotpath report from ${path}: ${error.message}`);
  }

  try {
    return JSON.parse(content);
  } catch (error) {
    fail(`Failed to parse hotpath report JSON from ${path}: ${error.message}`);
  }
}

function validateReports(before, after) {
  for (const [label, report] of [
    ["before", before],
    ["after", after],
  ]) {
    if (report.rspack_trace_layer !== "hotpath") {
      fail(
        `Expected ${label} report to be generated by hotpath layer, got ${report.rspack_trace_layer}`
      );
    }

    if (report.output_format !== "json") {
      fail(`Expected ${label} report to use json output, got ${report.output_format}`);
    }
  }

  if (JSON.stringify(before.percentiles) !== JSON.stringify(after.percentiles)) {
    fail(
      `Percentiles do not match: before=${JSON.stringify(before.percentiles)}, after=${JSON.stringify(after.percentiles)}`
    );
  }
}

function percentageDiff(before, after) {
  if (before === 0) {
    return after === 0 ? 0 : 100;
  }

  return ((after - before) / before) * 100;
}

function formatSignedPercentage(value) {
  const fixed = value.toFixed(1);
  return value < 0 ? fixed : `+${fixed}`;
}

function formatDurationNs(ns) {
  if (ns < 1_000) {
    return `${ns} ns`;
  }

  if (ns < 1_000_000) {
    return `${(ns / 1_000).toFixed(2)} us`;
  }

  if (ns < 1_000_000_000) {
    return `${(ns / 1_000_000).toFixed(2)} ms`;
  }

  return `${(ns / 1_000_000_000).toFixed(2)} s`;
}

function shortenName(name) {
  const parts = name.split("::");
  if (parts.length > 2) {
    return parts.slice(-2).join("::");
  }

  return name;
}

function zeroEntry(name) {
  return {
    name,
    calls: 0,
    avg_raw: 0,
    percentiles_raw: {},
    total_raw: 0,
    percent_total_raw: 0,
  };
}

function buildHeaders(percentiles) {
  return [
    "Function",
    "Avg",
    ...percentiles.map(percentile => `P${percentile}`),
    "Total",
    "% Total",
    "Calls",
  ];
}

function formatMetricDiff(kind, before, after) {
  if (kind === "calls") {
    return `${before} -> ${after} (${formatSignedPercentage(percentageDiff(before, after))}%)`;
  }

  if (kind === "percentage") {
    return `${(before / 100).toFixed(2)}% -> ${(after / 100).toFixed(2)}% (${formatSignedPercentage(
      percentageDiff(before, after)
    )}%)`;
  }

  return `${formatDurationNs(before)} -> ${formatDurationNs(after)} (${formatSignedPercentage(
    percentageDiff(before, after)
  )}%)`;
}

function buildFunctionDiff(name, before, after, percentiles) {
  const isNew = before == null;
  const isRemoved = after == null;
  const beforeEntry = before ?? zeroEntry(name);
  const afterEntry = after ?? zeroEntry(name);

  let displayName = shortenName(name);
  if (isNew) {
    displayName = `[new] ${displayName}`;
  } else if (isRemoved) {
    displayName = `[removed] ${displayName}`;
  }

  const cells = [
    displayName,
    formatMetricDiff("duration", beforeEntry.avg_raw, afterEntry.avg_raw),
  ];

  for (const percentile of percentiles) {
    const key = `p${percentile}`;
    cells.push(
      formatMetricDiff(
        "duration",
        beforeEntry.percentiles_raw[key] ?? 0,
        afterEntry.percentiles_raw[key] ?? 0
      )
    );
  }

  cells.push(formatMetricDiff("duration", beforeEntry.total_raw, afterEntry.total_raw));
  cells.push(
    formatMetricDiff(
      "percentage",
      beforeEntry.percent_total_raw,
      afterEntry.percent_total_raw
    )
  );
  cells.push(formatMetricDiff("calls", beforeEntry.calls, afterEntry.calls));

  return {
    functionName: name,
    importance: Math.max(beforeEntry.percent_total_raw, afterEntry.percent_total_raw),
    cells,
  };
}

function buildFunctionDiffs(before, after) {
  const beforeMap = new Map(before.data.map(entry => [entry.name, entry]));
  const afterMap = new Map(after.data.map(entry => [entry.name, entry]));
  const names = new Set([...beforeMap.keys(), ...afterMap.keys()]);

  return [...names]
    .map(name =>
      buildFunctionDiff(name, beforeMap.get(name), afterMap.get(name), before.percentiles)
    )
    .sort((left, right) => {
      if (left.importance !== right.importance) {
        return right.importance - left.importance;
      }

      if (left.functionName < right.functionName) {
        return -1;
      }

      if (left.functionName > right.functionName) {
        return 1;
      }

      return 0;
    });
}

function renderSeparator(widths) {
  return `+${widths.map(width => "-".repeat(width + 2)).join("+")}+\n`;
}

function renderRow(cells, widths, alignNumbersRight) {
  const formatted = cells.map((cell, index) => {
    const width = widths[index];
    const padding = width - cell.length;

    if (alignNumbersRight && index > 0) {
      return ` ${" ".repeat(padding)}${cell} `;
    }

    return ` ${cell}${" ".repeat(padding)} `;
  });

  return `|${formatted.join("|")}|\n`;
}

function renderTable(headers, rows) {
  const widths = headers.map(header => header.length);

  for (const row of rows) {
    row.forEach((cell, index) => {
      widths[index] = Math.max(widths[index], cell.length);
    });
  }

  let output = "";
  output += renderSeparator(widths);
  output += renderRow(headers, widths, false);
  output += renderSeparator(widths);

  for (const row of rows) {
    output += renderRow(row, widths, true);
  }

  output += renderSeparator(widths);
  return output;
}

function renderBenchDiff(before, after) {
  const headers = buildHeaders(before.percentiles);
  const rows = buildFunctionDiffs(before, after).map(diff => diff.cells);

  let output = "";
  output += "bench-diff - hotpath JSON comparison\n";
  output += `Description: ${before.description}\n`;
  output += `Overall elapsed: ${before.time_elapsed} -> ${after.time_elapsed} (${formatSignedPercentage(
    percentageDiff(before.total_elapsed_ns, after.total_elapsed_ns)
  )}%)\n`;
  output += renderTable(headers, rows);
  return `${output}\n`;
}

const [beforePath, afterPath] = process.argv.slice(2);
if (!beforePath || !afterPath) {
  fail("Usage: node .github/scripts/hotpath-bench-diff.mjs <before.json> <after.json>");
}

const before = loadReport(beforePath);
const after = loadReport(afterPath);
validateReports(before, after);
process.stdout.write(renderBenchDiff(before, after));
